mapper.select:
#{GRIDPAGING_ROWNUMTYPE_TOP}




			ORDER BY #{colName} DESC


			ORDER BY #{colName} ASC



			ORDER BY OWKEY , LCKEY , ICKEY , ULCKEY , IVATKEY    


#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

	/* wms-inventory-invnattrmod-sql-oracle.xml - selectIvatxlcxulcMap - 재고 조회  SQL */
		SELECT CTKEY
			 , OWKEY
			 , ICKEY
			 , LCKEY
			 , IVATKEY
			 , COALESCE(TTQTY, 0) AS TTQTY 
             , COALESCE(AVQTY, 0) AS AVQTY 
             , COALESCE(ALQTY, 0) AS ALQTY
             , COALESCE(PIQTY, 0) AS PIQTY
             , COALESCE(PAQTY, 0) AS PAQTY
             , COALESCE(LOQTY, 0) AS LOQTY
             , COALESCE(HOQTY, 0) AS HOQTY
		  FROM TWORK_INFO_IVATXLCXULC
		 WHERE CTKEY = #{ctkey}
		   AND OWKEY = #{owkey}
		   AND ICKEY = #{ickey}
		   AND LCKEY = #{lckey}
		   AND IVATKEY = #{ivatkey}
		   AND LCKEY NOT IN ('ASRS', 'MSC', 'STAGE', 'PICKTO')

mapper.insert:
/* wms-inventory-invnattrmod-sql-oracle.xml - insertTworkInfoIvat - 재고 속성 등록  SQL */
	INSERT INTO TWORK_INFO_IVAT 
		 (
		 CTKEY
		 , IVATKEY
		 , OWKEY
		 , ICKEY
		 , PRODUCTDATE
		 , EXPIREDATE
		 , ATTRIBUTE1
		 , ATTRIBUTE2
		 , ATTRIBUTE3
		 , ATTRIBUTE4
		 , ATTRIBUTE5
		 , PRODUCTLOT
		 , IVATSTATUS
		 , IBCONFIRMDATE
		 , LOGGRPCD
		 , ACKEY
		 , STORE_KEY
		 , ATTRIBUTE6
		 , ATTRIBUTE7
		 , ATTRIBUTE8
		 , ATTRIBUTE9
		 , IDNTFC_NO
		 , BDDR_GNRL_ITEM_IBYN
		 , CON_QTY
		 , NET_WGT
		 , CFQTY
		 , PLT_TYPE
		 , PLT_LOAD_QTY
		 , PLT_LOAD_HEIGHT
		 , UOM
		 , INSERTDATE
		 , INSERTURKEY
		 , UPDATEDATE
		 , UPDATEURKEY
		 ) VALUES 
		 (
		 #{ctkey}
		 , #{ivatkey}
		 , #{owkey}
		 , #{ickey}
		 , #{productdate}
		 , #{expiredate}
		 , #{attribute1}		/* TC/DC 구분 */
		 , #{attribute2}		/* 일반/보세 구분  */
		 , #{attribute3}
		 , #{attribute4}
		 , #{attribute5}
		 , #{productlot}
		 , #{ivatstatus}
		 , COALESCE(#{ibconfirmdate}, TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS'))
		 , COALESCE(#{loggrpcd}, '1')
		 , #{ackey}
		 , #{storeKey}
		 , #{attribute6}
		 , #{attribute7}
		 , #{attribute8}
		 , #{attribute9}
		 , #{idntfcNo}
		 , #{bddrGnrlItemIbyn}
		 , #{conQty}
		 , #{netWgt}
		 , #{cfqty}
		 , #{pltType}
		 , #{pltLoadQty}
		 , #{pltLoadHeight}
		 , #{chgUom}
		 , TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
		 , #{surkey}
		 , TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
		 , #{surkey}
		 )

mapper.update:
/* wms-inventory-invnattrmod-sql-oracle.xml - updateTworkInfoIncreIvat - 재고 속성 수정  SQL */
	UPDATE TWORK_INFO_IVAT
	   SET NET_WGT 		= NET_WGT + #{netWgt}
	     , CFQTY 		= CFQTY + #{cfqty} 
	     , UPDATEDATE 	= TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
		 , UPDATEURKEY 	= #{surkey}
	 WHERE CTKEY 		= #{ctkey}
	   AND OWKEY 		= #{owkey}
	   AND ICKEY 		= #{ickey}
	   AND IVATKEY 		= #{ivatkey}
	   AND UOM			= #{chgUom}

/* wms-inventory-invnattrmod-sql-oracle.xml - updateTworkInfoDecreIvat - 재고 속성 수정  SQL */
	UPDATE TWORK_INFO_IVAT
	   SET NET_WGT 		= NET_WGT - #{netWgt}
	     , CFQTY 		= CFQTY - #{cfqty} 
	     , UPDATEDATE 	= TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
		 , UPDATEURKEY 	= #{surkey}
	 WHERE CTKEY 		= #{ctkey}
	   AND OWKEY 		= #{owkey}
	   AND ICKEY 		= #{ickey}
	   AND IVATKEY 		= #{orgIvatkey}
	   AND UOM			= #{uom}

mapper.delete:
/* wms-inventory-invnattrmod-sql-oracle.xml - deleteTworkInfoIvat - 재고 속성 삭제  SQL */
	DELETE FROM TWORK_INFO_IVAT
	 WHERE CTKEY = #{ctkey}
	   AND OWKEY = #{owkey}
	   AND ICKEY = #{ickey}
	   AND IVATKEY = #{orgIvatkey}
	   AND UOM = #{uom}

mapper.select:
/* wms-inventory-invnattrmod-sql-oracle.xml - selectInfoIvatxlcxulcCount - 재고 조회  SQL */
	SELECT COUNT(*)
	  FROM TWORK_INFO_IVATXLCXULC
	 WHERE CTKEY = #{ctkey}
	   AND OWKEY = #{owkey}
	   AND ICKEY = #{ickey}
	   AND LCKEY = #{lckey}
	   AND IVATKEY = #{ivatkey}
	   AND LCKEY NOT IN ('ASRS', 'MSC', 'STAGE', 'PICKTO')

mapper.update:
/* wms-inventory-invnattrmod-sql-oracle.xml - updateIvatxlcxulcQty - 재고 수량 추가  SQL */
	UPDATE TWORK_INFO_IVATXLCXULC
	   SET TTQTY = COALESCE(TTQTY, 0) + COALESCE(#{ttqty}, 0)
	     , AVQTY = COALESCE(AVQTY, 0) + COALESCE(#{avqty}, 0)
	     , ALQTY = COALESCE(ALQTY, 0) + COALESCE(#{alqty}, 0)
	     , PIQTY = COALESCE(PIQTY, 0) + COALESCE(#{piqty}, 0)
	     , PAQTY = COALESCE(PAQTY, 0) + COALESCE(#{paqty}, 0)
	     , LOQTY = COALESCE(LOQTY, 0) + COALESCE(#{loqty}, 0)
	     , HOQTY = COALESCE(HOQTY, 0) + COALESCE(#{hoqty}, 0)
	     , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
		 , UPDATEURKEY = #{surkey}
	 WHERE CTKEY = #{ctkey}
	   AND OWKEY = #{owkey}
	   AND ICKEY = #{ickey}
	   AND LCKEY = #{lckey}
	   AND IVATKEY = #{ivatkey}
	   AND LCKEY NOT IN ('ASRS', 'MSC', 'STAGE', 'PICKTO')

/* wms-inventory-invnattrmod-sql-oracle.xml - updateIvatxlcxulcIvatkey - 재고 속성키 수정  SQL */
	UPDATE TWORK_INFO_IVATXLCXULC
	   SET IVATKEY = #{ivatkey}
	     , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
		 , UPDATEURKEY = #{surkey}
	 WHERE CTKEY = #{ctkey}
	   AND OWKEY = #{owkey}
	   AND ICKEY = #{ickey}
	   AND LCKEY = #{lckey}
	   AND IVATKEY = #{orgIvatkey}

mapper.delete:
/* wms-inventory-invnattrmod-sql-oracle.xml - deleteIvatxlcxulcIvatkey - 재고 삭제  SQL */
	DELETE FROM TWORK_INFO_IVATXLCXULC
	 WHERE CTKEY = #{ctkey}
	   AND OWKEY = #{owkey}
	   AND ICKEY = #{ickey}
	   AND LCKEY = #{lckey}
	   AND IVATKEY = #{orgIvatkey}

mapper.select:
	/* wms-inbound-invnattrmod-sql-oracle.xml - selectIvat - 재고 정보 조회 SQL */
		SELECT *
		  FROM TWORK_INFO_IVAT A
		 INNER JOIN TWORK_INFO_IVATXLCXULC B
		    ON A.CTKEY = B.CTKEY
		   AND A.OWKEY = B.OWKEY
		   AND A.ICKEY = B.ICKEY
		   AND A.IVATKEY = B.IVATKEY 
		 WHERE A.CTKEY            = #{ctkey}
           AND A.OWKEY            = #{owkey}
           AND B.LCKEY 			  = #{lckey}
           AND A.IVATKEY 		  = #{ivatkey}
